SELECT experiment_id
FROM experiments
WHERE version = (SELECT MAX(version) FROM experiments);

SELECT experiment_id
FROM experiments
WHERE researcher_id = 'R002';

SELECT COUNT(choice_presentation_id)
FROM choice_presentations
WHERE presentation_time <= 2;

SELECT duration AS total_duration
FROM trials
WHERE trial_id = 1;

SELECT COUNT(DISTINCT subject_id) AS unique_subjects, COUNT(DISTINCT choice_id) AS unique_choices
  FROM choices
  WHERE experiment_id = 1 AND choice_accuracy = 1;

SELECT COUNT(*)
FROM choice_presentations
WHERE experiment_id = 0 AND presentation_time > 5;
